import React, { useState, useEffect, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const API = process.env.REACT_APP_API_URL || "http://192.168.7.2:5000/api";

export default function ScanPage() {
  const { token } = useParams();

  const [data, setData]       = useState(null);
  const [error, setError]     = useState('');
  const [loading, setLoading] = useState(false);
  const [verified, setVerified] = useState(false);

  // ── Feature states ──
  const [speaking, setSpeaking]         = useState(false);
  const [location, setLocation]         = useState(null);
  const [locError, setLocError]         = useState('');
  const [smsSent, setSmsSent]           = useState(false);
  const [hospitals, setHospitals]       = useState([]);
  const [loadingHosp, setLoadingHosp]   = useState(false);
  const [hospError, setHospError]       = useState('');

  // ── Get location as soon as QR data loads ──
  useEffect(() => {
    if (!data) return;
    if (!navigator.geolocation) { setLocError('Geolocation not supported'); return; }
    navigator.geolocation.getCurrentPosition(
      (pos) => setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      ()    => setLocError('Location permission denied')
    );
  }, [data]);

  const handleVerify = async () => {
    setVerified(true);
    setLoading(true);
    try {
      const res = await axios.get(`${API}/public/scan/${token}`);
      setData(res.data);
    } catch (err) {
      setError(err.response?.data?.error || "Failed to load emergency information");
    } finally {
      setLoading(false);
    }
  };

  // ══════════════════════════════════════════
  // FEATURE 1 — Audio Emergency
  // ══════════════════════════════════════════
  const speakEmergency = useCallback(() => {
    if (!('speechSynthesis' in window)) { alert('Audio not supported on this browser'); return; }
    window.speechSynthesis.cancel();

    const p  = data?.profile || {};
    const c  = data?.contacts?.[0];
    const text = [
      'Emergency Alert!',
      p.full_name   ? `This person's name is ${p.full_name}.` : '',
      p.blood_type  ? `Blood group ${p.blood_type}.`          : '',
      p.allergies   ? `Allergic to ${p.allergies}.`           : '',
      p.medical_conditions ? `Medical condition: ${p.medical_conditions}.` : '',
      c             ? `Please call ${c.name}, their ${c.relationship}.` : '',
      'Call 108 for ambulance immediately.',
    ].filter(Boolean).join(' ');

    const utterance   = new SpeechSynthesisUtterance(text);
    utterance.lang    = 'en-IN';
    utterance.rate    = 0.88;
    utterance.pitch   = 1;
    utterance.onstart = () => setSpeaking(true);
    utterance.onend   = () => setSpeaking(false);
    utterance.onerror = () => setSpeaking(false);
    window.speechSynthesis.speak(utterance);
  }, [data]);

  const stopSpeaking = () => { window.speechSynthesis.cancel(); setSpeaking(false); };

  // ══════════════════════════════════════════
  // FEATURE 2 — Auto Location SMS to Family
  // ══════════════════════════════════════════
  const sendLocationSMS = () => {
    if (!location) { alert('Location not available yet. Please allow location access.'); return; }
    const p    = data?.profile || {};
    const c    = data?.contacts?.[0];
    if (!c)    { alert('No emergency contact found.'); return; }

    const mapsLink = `https://maps.google.com/?q=${location.lat},${location.lng}`;
    const msg = `🚨 EMERGENCY ALERT!\n${p.full_name || 'Someone'} has met with an accident.\n📍 Location: ${mapsLink}\n🩸 Blood Group: ${p.blood_type || 'Unknown'}\n⚠️ Allergies: ${p.allergies || 'None'}\nPlease come immediately!`;

    const phone = c.phone.replace(/\D/g, '');
    window.open(`sms:${phone}?body=${encodeURIComponent(msg)}`, '_blank');
    setSmsSent(true);
    setTimeout(() => setSmsSent(false), 4000);
  };

  // ══════════════════════════════════════════
  // FEATURE 3 — Nearest Hospital Finder
  // ══════════════════════════════════════════
  const findHospitals = () => {
    if (!location) { alert('Location not available. Please allow location access.'); return; }
    setLoadingHosp(true);
    setHospError('');

    // Open Google Maps with nearest hospitals
    window.open(
      `https://www.google.com/maps/search/hospital/@${location.lat},${location.lng},15z`,
      '_blank'
    );

    // Show static nearby options as fallback UI
    setTimeout(() => {
      setHospitals([
        { name: 'Nearest Government Hospital', dist: 'Check Maps', phone: '108' },
        { name: 'Sassoon General Hospital',    dist: 'Pune',       phone: '02026128000' },
        { name: 'Ambulance (National)',         dist: '—',          phone: '108' },
      ]);
      setLoadingHosp(false);
    }, 800);
  };

  // ── Styles ──
  const card = {
    background: '#1e293b', borderRadius: 16, padding: 20, marginTop: 16,
    boxShadow: '0 0 20px rgba(0,0,0,0.3)'
  };
  const btn = (bg = '#ef4444', extra = {}) => ({
    background: bg, border: 'none', padding: '10px 20px', borderRadius: 10,
    color: 'white', fontSize: 14, fontWeight: 'bold', cursor: 'pointer',
    display: 'inline-flex', alignItems: 'center', gap: 6, ...extra
  });

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(180deg, #0f172a, #020617)', padding: 20, color: 'white', fontFamily: 'sans-serif' }}>

      {/* Header */}
      <h1 style={{ textAlign: 'center', color: '#ef4444', marginBottom: 20 }}>🚨 Emergency Info</h1>

      {/* Verify Button */}
      {!verified && (
        <div style={{ textAlign: 'center', marginTop: 60 }}>
          <button onClick={handleVerify} style={btn('#ef4444', { padding: '14px 40px', fontSize: 16, boxShadow: '0 4px 20px rgba(239,68,68,0.4)' })}>
            🔐 Verify &amp; View
          </button>
        </div>
      )}

      {loading && <p style={{ textAlign: 'center', marginTop: 20 }}>Loading...</p>}
      {error   && <p style={{ textAlign: 'center', color: 'red', marginTop: 20 }}>{error}</p>}

      {data && (
        <>
          {/* ── Profile Card ── */}
          <div style={card}>
            <h2 style={{ marginBottom: 10 }}>👤 {data.profile?.full_name || 'No Name'}</h2>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              {data.profile?.gender         && <span>👩 {data.profile.gender}</span>}
              {data.profile?.date_of_birth  && <span>🎂 {data.profile.date_of_birth}</span>}
              {data.profile?.blood_type     && <span style={{ color: '#ef4444', fontWeight: 'bold' }}>🩸 {data.profile.blood_type}</span>}
              {data.profile?.address        && <span>📍 {data.profile.address}</span>}
            </div>
          </div>

          {/* ── Medical Info ── */}
          <div style={card}>
            <h3>🏥 Medical Info</h3>
            <p>⚠️ {data.profile?.allergies          || 'None'}</p>
            <p>🩺 {data.profile?.medical_conditions  || 'None'}</p>
            <p>💊 {data.profile?.current_medications || 'None'}</p>
            {data.profile?.doctor_name  && <p>👨‍⚕️ {data.profile.doctor_name}</p>}
            {data.profile?.doctor_phone && <p>📞 {data.profile.doctor_phone}</p>}
          </div>

          {/* ── Emergency Contacts ── */}
          {data.contacts?.length > 0 && (
            <div style={card}>
              <h3>📞 Emergency Contacts</h3>
              {data.contacts.map((c) => (
                <div key={c.id} style={{ marginTop: 10, padding: 10, borderRadius: 10, background: '#334155' }}>
                  <p style={{ marginBottom: 8 }}>{c.name} ({c.relationship})</p>
                  {/* Number hidden — call goes directly via tel: */}
                  <a href={`tel:${c.phone}`} style={{ textDecoration: 'none' }}>
                    <button style={btn('#ef4444')}>📞 Call Now</button>
                  </a>
                </div>
              ))}
            </div>
          )}

          {/* ════════════════════════════════════════
              FEATURE 1 — AUDIO EMERGENCY
          ════════════════════════════════════════ */}
          <div style={card}>
            <h3 style={{ marginBottom: 12 }}>🔊 Audio Emergency</h3>
            <p style={{ fontSize: 13, color: '#94a3b8', marginBottom: 14 }}>
              Phone will speak all emergency info aloud — useful if you are panicking or can't read.
            </p>
            {!speaking ? (
              <button onClick={speakEmergency} style={btn('#1d4ed8', { width: '100%', justifyContent: 'center', padding: 14 })}>
                🔊 Speak Emergency Info
              </button>
            ) : (
              <button onClick={stopSpeaking} style={btn('#64748b', { width: '100%', justifyContent: 'center', padding: 14 })}>
                ⏹ Stop Speaking...
              </button>
            )}
          </div>

          {/* ════════════════════════════════════════
              FEATURE 2 — AUTO LOCATION SMS
          ════════════════════════════════════════ */}
          <div style={card}>
            <h3 style={{ marginBottom: 12 }}>📍 Send Location to Family</h3>
            {location ? (
              <p style={{ fontSize: 13, color: '#4ade80', marginBottom: 14 }}>
                ✅ Location ready: {location.lat.toFixed(4)}, {location.lng.toFixed(4)}
              </p>
            ) : (
              <p style={{ fontSize: 13, color: '#f59e0b', marginBottom: 14 }}>
                ⏳ {locError || 'Getting location... Please allow access.'}
              </p>
            )}
            <button
              onClick={sendLocationSMS}
              disabled={!location}
              style={btn(location ? '#16a34a' : '#374151', { width: '100%', justifyContent: 'center', padding: 14, opacity: location ? 1 : 0.6 })}
            >
              {smsSent ? '✅ SMS App Opened!' : '📲 Send Location SMS to Family'}
            </button>
            <p style={{ fontSize: 11, color: '#64748b', marginTop: 8, textAlign: 'center' }}>
              Opens SMS app with accident location + medical info pre-filled
            </p>
          </div>

          {/* ════════════════════════════════════════
              FEATURE 3 — NEAREST HOSPITAL
          ════════════════════════════════════════ */}
          <div style={card}>
            <h3 style={{ marginBottom: 12 }}>🏥 Find Nearest Hospital</h3>
            <button
              onClick={findHospitals}
              disabled={loadingHosp}
              style={btn('#7c3aed', { width: '100%', justifyContent: 'center', padding: 14 })}
            >
              {loadingHosp ? '⏳ Finding...' : '🏥 Find Nearest Hospitals'}
            </button>

            {hospError && <p style={{ color: 'red', fontSize: 13, marginTop: 8 }}>{hospError}</p>}

            {hospitals.length > 0 && (
              <div style={{ marginTop: 14, display: 'flex', flexDirection: 'column', gap: 10 }}>
                {hospitals.map((h, i) => (
                  <div key={i} style={{ background: '#334155', borderRadius: 10, padding: '10px 14px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: 14 }}>🏥 {h.name}</div>
                      <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 2 }}>📍 {h.dist}</div>
                    </div>
                    <a href={`tel:${h.phone}`} style={{ textDecoration: 'none' }}>
                      <button style={btn('#7c3aed', { padding: '8px 14px', fontSize: 12 })}>📞 Call</button>
                    </a>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* ── National Emergency Numbers ── */}
          <div style={card}>
            <h3 style={{ marginBottom: 12 }}>🚨 National Emergency</h3>
            <div style={{ display: 'flex', gap: 10 }}>
              {[{ label: '🚑 108', num: '108' }, { label: '🚔 112', num: '112' }, { label: '👮 100', num: '100' }].map(e => (
                <a key={e.num} href={`tel:${e.num}`} style={{ flex: 1, textDecoration: 'none' }}>
                  <button style={{ ...btn('#1e293b'), width: '100%', justifyContent: 'center', border: '1px solid #ef4444', padding: '12px 6px', fontSize: 13 }}>
                    {e.label}
                  </button>
                </a>
              ))}
            </div>
          </div>

        </>
      )}
    </div>
  );
}
